        <h3 className="tomasRadic">TOMAS RADIC</h3>
        <Nav />
      </div>
      <div className="body">
        <h1 className="tomRadText">
          Hello, I am Tomas Radic, front-End developer
        </h1>
        <Slider number={0} />
      </div>
    </div>
  );
}

export default App;
